Office.onReady(() => {
  // ผูกชื่อ handler ให้ตรงกับ FunctionName ใน manifest
  Office.actions.associate("onAppointmentSendHandler", onAppointmentSendHandler);
});

const AMENITIES_BODY_MARKER_PREFIX = "<!--ROOM_SERVICES:";
const AMENITIES_BODY_MARKER_SUFFIX = "-->";

/**
 * Returns true when amenities payload object has at least one entry.
 */
function hasAmenitiesPayload(payload) {
  return Boolean(payload && typeof payload === "object" && Object.keys(payload).length > 0);
}

/**
 * Parses JSON text and returns a safe object payload.
 */
function parsePayload(raw, sourceLabel) {
  if (!raw || typeof raw !== "string") return {};
  try {
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch (error) {
    console.warn(`${sourceLabel} is not valid JSON:`, error);
    return {};
  }
}

/**
 * Decodes body marker payload into an amenities object.
 */
function decodeBodyMarkerPayload(encoded) {
  if (!encoded || typeof encoded !== "string") return {};
  try {
    const jsonText = decodeURIComponent(escape(atob(encoded)));
    return parsePayload(jsonText, "body marker");
  } catch (error) {
    console.warn("Body marker payload decode failed:", error);
    return {};
  }
}

/**
 * Reads the current compose body as HTML text.
 */
function readBodyHtmlAsync(item) {
  return new Promise((resolve) => {
    if (!item || !item.body || typeof item.body.getAsync !== "function") return resolve("");
    item.body.getAsync(Office.CoercionType.Html, (res) => {
      if (res.status !== Office.AsyncResultStatus.Succeeded) return resolve("");
      resolve(typeof res.value === "string" ? res.value : "");
    });
  });
}

/**
 * Extracts amenities payload from hidden marker inside body HTML.
 */
function extractPayloadFromBodyHtml(html) {
  if (!html || typeof html !== "string") return {};

  // Legacy comment marker.
  const start = html.indexOf(AMENITIES_BODY_MARKER_PREFIX);
  if (start >= 0) {
    const payloadStart = start + AMENITIES_BODY_MARKER_PREFIX.length;
    const end = html.indexOf(AMENITIES_BODY_MARKER_SUFFIX, payloadStart);
    if (end >= 0) {
      const encodedLegacy = html.slice(payloadStart, end).trim();
      const payloadLegacy = decodeBodyMarkerPayload(encodedLegacy);
      if (hasAmenitiesPayload(payloadLegacy)) return payloadLegacy;
    }
  }

  // Current hidden div marker.
  const tokenRegex = /RSU_AMENITIES_B64:([A-Za-z0-9+/=]+)/i;
  const match = html.match(tokenRegex);
  if (!match || !match[1]) return {};
  return decodeBodyMarkerPayload(match[1]);
}

/**
 * Reads amenities payload from hidden body marker.
 */
async function readAmenitiesFromBodyMarker(item) {
  const html = await readBodyHtmlAsync(item);
  return extractPayloadFromBodyHtml(html);
}

/**
 * Handles send-time processing and forwards event data with amenities to backend flow.
 */
async function onAppointmentSendHandler(event) {
  try {
    const item = Office.context.mailbox.item;

    const roomServicesFromBody = await readAmenitiesFromBodyMarker(item);

    // โหลด custom properties ที่ task pane เก็บไว้หลังรายการมี itemId แล้ว
    const props = await loadProps(item);
    const roomServicesFromProps =
      props && props.get("roomServices") ? parsePayload(props.get("roomServices"), "roomServices") : {};
    const roomServices = hasAmenitiesPayload(roomServicesFromBody) ? roomServicesFromBody : roomServicesFromProps;

    // สร้าง payload รวมข้อมูลพื้นฐานจากนัด
    const payload = {
      subject: item.subject,
      start: item.start,
      end: item.end,
      location: item.location ? item.location.displayName : "",

      organizer: Office.context.mailbox.userProfile.emailAddress,
      ...roomServices
    };

    // TODO: ใส่ URL ของ Power Automate (HTTPS เท่านั้น)
    const PA_URL = "<<PA_URL>>";

    // ยิงไป Power Automate / backend (รองรับ CORS/ใบรับรอง)
    const res = await fetch(PA_URL, {
      method: "POST",
      headers: {"Content-Type": "application/json"},
      body: JSON.stringify(payload)
    });

    if (!res.ok) {
      const text = await res.text().catch(() => "");
      // เลือก: จะบล็อกการส่งนัดหรือไม่
      return event.completed({
        allowEvent: false,
        errorMessage: `Amenities request failed: HTTP ${res.status} ${res.statusText} ${text.slice(0,160)}`
      });
    }

    // อนุญาตให้ส่งนัดต่อ
    event.completed({ allowEvent: true });

  } catch (e) {
    // ปล่อยให้ส่งต่อ (หรือจะแจ้ง block ก็ได้)
    event.completed({ allowEvent: true });
  }
}

/**
 * Loads custom properties for the current item in compose mode.
 */
function loadProps(item) {
  return new Promise((resolve) => {
    item.loadCustomPropertiesAsync((res) => {
      if (res.status === Office.AsyncResultStatus.Succeeded) resolve(res.value);
      else resolve(null);
    });
  });
}
